import{_ as d,o as r,c as a,ag as e}from"./chunks/framework.wqPkq5Rj.js";const b=JSON.parse('{"title":"一种信息多种表达","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/multi-format.md","filePath":"advanced/multi-format.md","lastUpdated":1777171400000}'),o={name:"advanced/multi-format.md"};function i(l,t,h,n,p,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="一种信息多种表达" tabindex="-1">一种信息多种表达 <a class="header-anchor" href="#一种信息多种表达" aria-label="Permalink to &quot;一种信息多种表达&quot;">​</a></h1><p>信息本身没有固定形态——同一份内容，面对不同读者、不同场景，可以有完全不同的呈现方式。</p><p>这里用一份真实的 <strong>AI 工具渗透率数据</strong> 作为素材，展示 momo 如何把同一批内容转化成四种形式：文字报告适合阅读和引用，热力地图适合直觉感受地区差异，翻页报告适合有节奏地汇报，交互看板适合自由探索数据。</p><p>你不需要重新整理素材，只需要告诉 momo 你想要什么形式。</p><hr><h2 id="四种表达形式" tabindex="-1">四种表达形式 <a class="header-anchor" href="#四种表达形式" aria-label="Permalink to &quot;四种表达形式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>形式</th><th>适合场景</th></tr></thead><tbody><tr><td>文字报告</td><td>阅读、引用数据、快速获取结论</td></tr><tr><td>世界热力图</td><td>直觉感受地区差异，点击国家查详情</td></tr><tr><td>翻页报告</td><td>有故事线的逐步揭示，适合汇报</td></tr><tr><td>交互式仪表盘</td><td>自由探索多维数据，适合分析</td></tr></tbody></table><hr><h2 id="文字报告-ai-工具渗透率-·-2025-全球概览" tabindex="-1">文字报告：AI 工具渗透率 · 2025 全球概览 <a class="header-anchor" href="#文字报告-ai-工具渗透率-·-2025-全球概览" aria-label="Permalink to &quot;文字报告：AI 工具渗透率 · 2025 全球概览&quot;">​</a></h2><h3 id="核心数据" tabindex="-1">核心数据 <a class="header-anchor" href="#核心数据" aria-label="Permalink to &quot;核心数据&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数值</th><th>同比变化</th></tr></thead><tbody><tr><td>全球企业 AI 采用率</td><td><strong>88%</strong></td><td>+10pp</td></tr><tr><td>员工日常使用 AI 工具比例</td><td><strong>75%</strong></td><td>+14pp</td></tr><tr><td>AI 采用率最高国家</td><td>阿联酋 93%</td><td>—</td></tr><tr><td>采用率增长最快地区</td><td>南亚 / 东南亚</td><td>+18–22pp</td></tr></tbody></table><h3 id="地区格局" tabindex="-1">地区格局 <a class="header-anchor" href="#地区格局" aria-label="Permalink to &quot;地区格局&quot;">​</a></h3><p><strong>高渗透区（≥ 70%）</strong> — 新兴市场领跑，政府主导 + 年轻人口是共同驱动因素。</p><table tabindex="0"><thead><tr><th>国家</th><th>采用率</th><th>核心驱动力</th></tr></thead><tbody><tr><td>阿联酋</td><td>93%</td><td>国家 AI 战略、G42、非油经济转型</td></tr><tr><td>印度</td><td>85%</td><td>IT 外包转型、Krutrim/Sarvam 本土 LLM</td></tr><tr><td>新加坡</td><td>85%</td><td>东南亚 AI 枢纽、亚太监管框架</td></tr><tr><td>中国</td><td>82%</td><td>DeepSeek 开源生态、豆包/Kimi 应用爆发</td></tr><tr><td>韩国</td><td>80%</td><td>半导体 AI、Naver HyperCLOVA</td></tr><tr><td>沙特</td><td>78%</td><td>Vision 2030、NEOM 智慧城市</td></tr><tr><td>巴西</td><td>76%</td><td>Pix 金融 AI、农业精准化</td></tr></tbody></table><p><strong>中渗透区（50–69%）</strong> — 发达经济体受监管与遗留系统制约，增速低于新兴市场。</p><table tabindex="0"><thead><tr><th>国家/地区</th><th>采用率</th><th>主要阻力</th></tr></thead><tbody><tr><td>美国</td><td>72%</td><td>遗留系统、监管不确定性</td></tr><tr><td>以色列</td><td>76%</td><td>安全 AI 主导，军转民生态成熟</td></tr><tr><td>法国</td><td>65%</td><td>GDPR、欧盟 AI Act</td></tr><tr><td>澳大利亚</td><td>65%</td><td>Canva 带动创意行业领跑</td></tr><tr><td>英国</td><td>60%</td><td>审慎文化、脱欧人才流失</td></tr><tr><td>德国</td><td>55%</td><td>数据合规、Mittelstand 转型慢</td></tr></tbody></table><h3 id="三个值得关注的反差" tabindex="-1">三个值得关注的反差 <a class="header-anchor" href="#三个值得关注的反差" aria-label="Permalink to &quot;三个值得关注的反差&quot;">​</a></h3><p><strong>1. 新兴市场反超发达国家</strong></p><p>阿联酋（93%）&gt; 美国（72%）&gt; 德国（55%）。监管宽松 + 无遗留系统包袱，使新兴市场能更快全面切换。</p><p><strong>2. 日本是 G7 异类</strong></p><p>唯一采用率低于 55% 的 G7 成员（51%），根因是企业文化（传真机仍在用）而非技术能力缺失。2024 年政府&quot;DX&quot;转型推动快速补课。</p><p><strong>3. 非洲跳跃式渗透</strong></p><p>尼日利亚（68%）、肯尼亚（63%）、南非（62%）——银行账户低渗透率反而加速 AI 金融普惠，移动端 AI 直接跳过 PC 时代。</p><h3 id="行业分布-全球" tabindex="-1">行业分布（全球） <a class="header-anchor" href="#行业分布-全球" aria-label="Permalink to &quot;行业分布（全球）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行业</th><th>AI 采用率</th><th>典型用途</th></tr></thead><tbody><tr><td>科技 / 软件</td><td>~95%</td><td>代码生成、产品设计</td></tr><tr><td>金融服务</td><td>~88%</td><td>风控、客服、合规</td></tr><tr><td>医疗健康</td><td>~72%</td><td>影像诊断、临床辅助</td></tr><tr><td>制造业</td><td>~68%</td><td>质检、供应链、设计</td></tr><tr><td>教育</td><td>~65%</td><td>个性化学习、批改</td></tr><tr><td>政府 / 公共部门</td><td>~58%</td><td>文件处理、公民服务</td></tr></tbody></table><h3 id="主流工具格局" tabindex="-1">主流工具格局 <a class="header-anchor" href="#主流工具格局" aria-label="Permalink to &quot;主流工具格局&quot;">​</a></h3><p><strong>全球通用层</strong>（跨地区高渗透）：ChatGPT · Microsoft Copilot · GitHub Copilot · Google Gemini</p><p><strong>本土替代层</strong>（主权 AI / 本地合规驱动）：</p><ul><li>中国：DeepSeek · 文心一言 · 通义千问 · 豆包 · Kimi</li><li>韩国：Naver HyperCLOVA X · Kakao AI</li><li>法国：Mistral AI</li><li>印度：Krutrim · Sarvam AI（支持 10+ 本土语言）</li></ul><div class="info custom-block"><p class="custom-block-title">数据来源</p><p>McKinsey &amp; Company (2025). <em>The State of AI: Global Survey 2025</em> Stanford HAI (2025). <em>AI Index Report 2025</em> Microsoft AI Economy Institute (2025). <em>AI Economic Impact H2 2025</em></p></div><hr><h2 id="世界热力图" tabindex="-1">世界热力图 <a class="header-anchor" href="#世界热力图" aria-label="Permalink to &quot;世界热力图&quot;">​</a></h2><p>同一份数据，用地图形式呈现全球各国的 AI 采用率。颜色越深，渗透率越高。点击国家可以查看详情。</p><iframe src="../multi-format/heatmap.html" width="100%" height="650" style="border:1px solid var(--vp-c-divider);border-radius:12px;margin:16px 0;"></iframe><p><a href="../multi-format/heatmap.html" target="_blank" style="display:inline-block;margin-bottom:32px;color:var(--vp-c-brand-1);">↗ 全屏查看</a></p><hr><h2 id="翻页报告" tabindex="-1">翻页报告 <a class="header-anchor" href="#翻页报告" aria-label="Permalink to &quot;翻页报告&quot;">​</a></h2><p>适合有节奏的汇报场景。同样的数据，按叙事逻辑逐步揭示，像 PPT 一样翻页浏览。</p><iframe src="../multi-format/slide-report.html" width="100%" height="650" style="border:1px solid var(--vp-c-divider);border-radius:12px;margin:16px 0;"></iframe><p><a href="../multi-format/slide-report.html" target="_blank" style="display:inline-block;margin-bottom:32px;color:var(--vp-c-brand-1);">↗ 全屏查看</a></p><hr><h2 id="交互式仪表盘" tabindex="-1">交互式仪表盘 <a class="header-anchor" href="#交互式仪表盘" aria-label="Permalink to &quot;交互式仪表盘&quot;">​</a></h2><p>自由探索多维数据。支持筛选、切换视图、缩放图表——适合需要深入分析的场景。</p><iframe src="../multi-format/dashboard.html" width="100%" height="650" style="border:1px solid var(--vp-c-divider);border-radius:12px;margin:16px 0;"></iframe><p><a href="../multi-format/dashboard.html" target="_blank" style="display:inline-block;margin-bottom:32px;color:var(--vp-c-brand-1);">↗ 全屏查看</a></p><hr><p>以上四种形式——文字报告、热力地图、翻页报告、交互看板——来自完全相同的一份数据。你不需要重新整理素材，只需要告诉 momo 你想要什么形式。</p>',47)])])}const c=d(o,[["render",i]]);export{b as __pageData,c as default};
